"""Unit tests for reliability-related database engine configuration."""

from __future__ import annotations

from app.db import _connect_args, _database_url, _engine_kwargs


def test_sqlite_connect_args_disable_same_thread_check():
    assert _connect_args("sqlite:///./url_shortener.db") == {"check_same_thread": False}


def test_postgres_connect_args_set_a_bounded_connect_timeout():
    url = "postgresql+psycopg://user:pw@host:5432/db"
    assert _connect_args(url) == {"connect_timeout": 5}


def test_engine_kwargs_enable_pool_pre_ping_for_sqlite():
    kwargs = _engine_kwargs("sqlite:///./url_shortener.db")
    assert kwargs["pool_pre_ping"] is True
    assert kwargs["connect_args"] == {"check_same_thread": False}


def test_engine_kwargs_enable_pool_pre_ping_for_postgres():
    url = "postgresql+psycopg://user:pw@host:5432/db"
    kwargs = _engine_kwargs(url)
    assert kwargs["pool_pre_ping"] is True
    assert kwargs["connect_args"] == {"connect_timeout": 5}


def test_database_url_defaults_to_sqlite_without_postgres_env(monkeypatch):
    monkeypatch.delenv("DATABASE_URL", raising=False)
    monkeypatch.delenv("POSTGRES_USER", raising=False)
    assert _database_url() == "sqlite:///./url_shortener.db"


def test_database_url_uses_explicit_override(monkeypatch):
    monkeypatch.setenv("DATABASE_URL", "postgresql+psycopg://x:y@z:5432/db")
    assert _database_url() == "postgresql+psycopg://x:y@z:5432/db"


def test_database_url_builds_from_postgres_env(monkeypatch):
    monkeypatch.delenv("DATABASE_URL", raising=False)
    monkeypatch.setenv("POSTGRES_USER", "app")
    monkeypatch.setenv("POSTGRES_PASSWORD", "secret")
    monkeypatch.setenv("POSTGRES_HOST", "db-host")
    monkeypatch.setenv("POSTGRES_PORT", "5433")
    monkeypatch.setenv("POSTGRES_DB", "shortener")
    assert _database_url() == "postgresql+psycopg://app:secret@db-host:5433/shortener"
